// ========================================================================
//  TRUESEAT - Client-Deliverable shared tokens (Hiring Playbook + Culture Codified)
//
//  Self-contained design tokens for the RAC-standard client deliverables.
//  Mirrors debrief-engine.js's self-contained principle, but EMBEDS the Arimo
//  webfont as base64 @font-face so the render is deterministic regardless of
//  what fonts the render server's Chromium has.
//
//  Font decision (locked): Arimo-first. Arimo is metric-compatible with Helvetica,
//  OFL-clean to embed, ships 400/700. The render server has no Helvetica Neue, so
//  the existing engine PDFs already resolve to a Helvetica-metric fallback today;
//  Arimo-first makes that explicit and kills the one divergence case (a designer's
//  Mac WITH Helvetica rendering different glyphs than the server).
//
//  900-weight caveat: Arimo ships 400/700. font-weight:900 resolves to 700 bold,
//  exactly what current platform PDFs already produce on the server. A genuine 900
//  face must be added here only if display headlines ever need to be HEAVIER.
//
//  License: Arimo is SIL OFL 1.1. Redistribution (incl. embedding) permitted with
//  the license retained. See OFL.txt in the renderer repo root.
// ========================================================================

const ARIMO_FONT_FACE = `
@font-face{
  font-family:'Arimo'; font-style:normal; font-weight:400; font-display:swap;
  src:url(data:font/woff2;base64,) format('woff2');
}
@font-face{
  font-family:'Arimo'; font-style:normal; font-weight:700; font-display:swap;
  src:url(data:font/woff2;base64,) format('woff2');
}
`;

// Arimo-first: embed is authoritative on every machine; Helvetica is a fallback
// reached only off the render path. Metric-compatible, so layout holds identically
// even if the embed somehow fails to load.
const DELIVERABLE_FONT_STACK = "'Arimo','Helvetica Neue',Helvetica,Arial,sans-serif";

module.exports = { ARIMO_FONT_FACE, DELIVERABLE_FONT_STACK };
